const Metadata_Context = $("Metadata & Context").first().json;
const Quantitative_Scoring = $("Quantitative Scoring").first().json;
const Qualitative_Analysis_Diagnosis = $("Qualitative Analysis & Diagnosis").first().json;
const Execution_Recommendation = $("Execution & Recommendation").first().json;
const SWOT = $("SWOT").first().json;

// 2. تجميع الحقول الموحدة المطلوبة للإيميل والـ IF
return [
  {
    json: {
      // جلب الـ ID من أي شيت متاح فيه
      ID: Metadata_Context.ID || Quantitative_Scoring.ID || Qualitative_Analysis_Diagnosis.ID || Execution_Recommendation.ID || SWOT.ID, 

      // جلب اسم القرار (يدعم التسمية العادية أو التسمية الخاصة بالـ AI)
      Decision: Metadata_Context.Decision || Metadata_Context.decision_title || Quantitative_Scoring.Decision || Quantitative_Scoring.decision_title || Qualitative_Analysis_Diagnosis.Decision || Qualitative_Analysis_Diagnosis.decision_title || Execution_Recommendation.Decision || Execution_Recommendation.decision_title || SWOT.Decision || SWOT.decision_title, 

      // جلب التوقيت (من الشيت الأساسي أو شيتات التقييم، وإذا لم يوجد يضع الوقت الحالي)
      Timestamp: Metadata_Context.Timestamp || Metadata_Context.date || Quantitative_Scoring.Timestamp || Quantitative_Scoring.date || new Date().toISOString(), 

      // جلب الأولوية من شيت التحليل النوعي أو شيت التوصيات
      Priority: Qualitative_Analysis_Diagnosis.Priority || Execution_Recommendation.Priority || "Medium", 

      // جلب خطة العمل من شيت التوصيات التنفيذية
      Action_Plan: Execution_Recommendation.Action_Plan || Execution_Recommendation['Action Plan'] || "لا يوجد خطة عمل حالية"
    }
  }
];

// دالة مساعدة لجلب البيانات بأمان دون كسر الكود إذا كانت العقدة غير مفعلة أو لم يتم المرور عليها
function getSafeJson(nodeName) {
  try {
    const node = $(nodeName);
    if (node && typeof node.first === 'function') {
      const firstItem = node.first();
      if (firstItem && firstItem.json) {
        return firstItem.json;
      }
    }
  } catch (e) {
    // في حال عدم وجود العقدة في المسار الحالي (مثل حالات الحذف) يتم تجاهل الخطأ وإرجاع كائن فارغ
  }
  return {};
}

// 1. جلب البيانات بأمان من كافة العقد والشيتات المتفرقة
const Metadata_Context = getSafeJson("Metadata & Context");
const Quantitative_Scoring = getSafeJson("Quantitative Scoring");
const Qualitative_Analysis_Diagnosis = getSafeJson("Qualitative Analysis & Diagnosis");
const Execution_Recommendation = getSafeJson("Execution & Recommendation");
const SWOT = getSafeJson("SWOT");

// 2. تجميع الحقول الموحدة (ستأخذ قيمتها من الشيت النشط فقط سواء كان تحليل أو حذف)
return [
  {
    json: {
      // جلب الـ ID من الشيت المتوفر حالياً
      ID: Metadata_Context.ID || Quantitative_Scoring.ID || Qualitative_Analysis_Diagnosis.ID || Execution_Recommendation.ID || SWOT.ID || null, 

      // جلب اسم القرار أو موضوع الحذف المتوفر
      Decision: Metadata_Context.Decision || Metadata_Context.decision_title || 
                Quantitative_Scoring.Decision || Quantitative_Scoring.decision_title || 
                Qualitative_Analysis_Diagnosis.Decision || Qualitative_Analysis_Diagnosis.decision_title || 
                Execution_Recommendation.Decision || Execution_Recommendation.decision_title || 
                SWOT.Decision || SWOT.decision_title || "إجراء حذف / تعديل مقيد", 

      // جلب التوقيت المتاح، أو وضع التوقيت الحالي
      Timestamp: Metadata_Context.Timestamp || Metadata_Context.date || 
                 Quantitative_Scoring.Timestamp || Quantitative_Scoring.date || 
                 Qualitative_Analysis_Diagnosis.Timestamp || Execution_Recommendation.Timestamp ||
                 new Date().toISOString(), 

      // جلب الأولوية إن وجدت
      Priority: Qualitative_Analysis_Diagnosis.Priority || Execution_Recommendation.Priority || "Medium", 

      // جلب خطة العمل إن وجدت
      Action_Plan: Execution_Recommendation.Action_Plan || Execution_Recommendation['Action Plan'] || "تم تنفيذ إجراء الحذف بنجاح"
    }
  }
];

